#include <iostream>
#include <vector>
#include <memory>
#include <algorithm>

using namespace std;

class Entity {
public:
    Entity() { cout << "Entity Created\n"; }
    ~Entity() { cout << "Entity Destroyed\n"; }
    void greet() { cout << "Hello from Entity!\n"; }
};

int main() {
    cout << "--- Smart Pointers ---\n";
    {
        // Scope block
        unique_ptr<Entity> entity = make_unique<Entity>();
        entity->greet();
    } 
    // Entity is automatically destroyed here because scope ended!
    cout << "(Entity should be destroyed above)\n";

    cout << "\n--- Lambdas & Auto ---\n";
    vector<int> numbers = {5, 2, 8, 1, 9};

    // Sort using lambda
    sort(numbers.begin(), numbers.end(), [](int a, int b) {
        return a > b; // Descending order
    });

    cout << "Sorted: ";
    for(auto n : numbers) {
        cout << n << " ";
    }
    cout << endl;

    return 0;
}
